/* Minimal ZIP helper for LMA Dog Trainer.
   Supports STORE-only ZIP creation and extraction for files generated by this app. */
(function(global){
  function crc32(buf){
    let table = crc32.table;
    if(!table){
      table = crc32.table = new Uint32Array(256);
      for(let i=0;i<256;i++){
        let c=i;
        for(let k=0;k<8;k++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
        table[i]=c>>>0;
      }
    }
    let c=0xffffffff;
    for(let i=0;i<buf.length;i++) c = table[(c ^ buf[i]) & 255] ^ (c >>> 8);
    return (c ^ 0xffffffff) >>> 0;
  }
  function enc(str){ return new TextEncoder().encode(str); }
  function u16(n){ return [n & 255, (n>>>8)&255]; }
  function u32(n){ return [n & 255, (n>>>8)&255, (n>>>16)&255, (n>>>24)&255]; }
  function dosTimeDate(d=new Date()){
    const time = ((d.getHours() & 31) << 11) | ((d.getMinutes() & 63) << 5) | ((Math.floor(d.getSeconds()/2)) & 31);
    const date = (((d.getFullYear()-1980) & 127) << 9) | (((d.getMonth()+1) & 15) << 5) | (d.getDate() & 31);
    return {time,date};
  }
  function concat(chunks){
    const len = chunks.reduce((a,b)=>a+b.length,0);
    const out = new Uint8Array(len);
    let off=0; for(const c of chunks){ out.set(c,off); off+=c.length; }
    return out;
  }
  function zipSync(files){
    const local = [], central = [];
    let offset = 0;
    const dt = dosTimeDate();
    for(const name of Object.keys(files)){
      const data = files[name] instanceof Uint8Array ? files[name] : new Uint8Array(files[name]);
      const nameBytes = enc(name);
      const crc = crc32(data);
      const localHeader = new Uint8Array([
        ...u32(0x04034b50), ...u16(20), ...u16(0), ...u16(0),
        ...u16(dt.time), ...u16(dt.date), ...u32(crc),
        ...u32(data.length), ...u32(data.length),
        ...u16(nameBytes.length), ...u16(0)
      ]);
      local.push(localHeader, nameBytes, data);
      const centralHeader = new Uint8Array([
        ...u32(0x02014b50), ...u16(20), ...u16(20), ...u16(0), ...u16(0),
        ...u16(dt.time), ...u16(dt.date), ...u32(crc),
        ...u32(data.length), ...u32(data.length),
        ...u16(nameBytes.length), ...u16(0), ...u16(0), ...u16(0), ...u16(0),
        ...u32(0), ...u32(offset)
      ]);
      central.push(centralHeader, nameBytes);
      offset += localHeader.length + nameBytes.length + data.length;
    }
    const centralStart = offset;
    const centralBlob = concat(central);
    const end = new Uint8Array([
      ...u32(0x06054b50), ...u16(0), ...u16(0),
      ...u16(Object.keys(files).length), ...u16(Object.keys(files).length),
      ...u32(centralBlob.length), ...u32(centralStart), ...u16(0)
    ]);
    return concat([...local, centralBlob, end]);
  }
  function readU16(b,o){ return b[o] | (b[o+1]<<8); }
  function readU32(b,o){ return (b[o] | (b[o+1]<<8) | (b[o+2]<<16) | (b[o+3]<<24)) >>> 0; }
  function unzipSync(buf){
    const out = {};
    let o = 0;
    const dec = new TextDecoder();
    while(o < buf.length - 4){
      const sig = readU32(buf,o);
      if(sig !== 0x04034b50) break;
      const method = readU16(buf,o+8);
      const compSize = readU32(buf,o+18);
      const nameLen = readU16(buf,o+26);
      const extraLen = readU16(buf,o+28);
      const name = dec.decode(buf.slice(o+30,o+30+nameLen));
      const dataStart = o + 30 + nameLen + extraLen;
      const data = buf.slice(dataStart, dataStart + compSize);
      if(method !== 0) throw new Error("This lightweight importer only supports uncompressed ZIP files made by this app.");
      out[name] = data;
      o = dataStart + compSize;
    }
    return out;
  }
  global.fflate = { zipSync, unzipSync };
})(self);